import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  city: string;
  temperatureText: string;
  condition: string;
  conditionIcon: string;
  humidityText: string;
  windText: string;
  unit: string;
  forecast: Array<{ day: string; icon: string; highText: string; lowText: string }>;
}

function getConditionIcon(condition: string): string {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return '❄️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  return '🌤️';
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  // add your state, effects, and wire hook logic here

  // DO NOT EDIT wire hooks below — auto-generated from the data contract


  const forecast = useMemo(() => {
    const normalized = props.forecast.slice(0, 5).map((item, index) => ({
      day: item.day ?? `Day ${index + 1}`,
      icon: item.icon ?? getConditionIcon(props.condition),
      highText: `${item.high ?? '--'}°${props.unit}`,
      lowText: `${item.low ?? '--'}°${props.unit}`,
    }));

    while (normalized.length < 5) {
      const index = normalized.length;
      normalized.push({
        day: `Day ${index + 1}`,
        icon: getConditionIcon(props.condition),
        highText: `--°${props.unit}`,
        lowText: `--°${props.unit}`,
      });
    }

    return normalized;
  }, [props.forecast, props.condition, props.unit]);

  return {
    city: props.city,
    temperatureText: `${props.temperature}°${props.unit}`,
    condition: props.condition,
    conditionIcon: getConditionIcon(props.condition),
    humidityText: `${props.humidity}%`,
    windText: `${props.windSpeed} ${props.unit === 'C' ? 'km/h' : 'mph'}`,
    unit: props.unit,
    forecast,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // add any UI-only state here (tabs, accordions, scroll position, etc.)

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Card
          padding="var(--ggui-spacing-6, 24px)"
          radius="xl"
          shadow="md"
          border
        >
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Row justify="between" align="start">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Current Weather
                </Text>
                <Heading level={2}>{props.city}</Heading>
              </Stack>
              <Badge variant="info" size="md">
                {props.unit === 'C' ? 'Metric' : 'Imperial'}
              </Badge>
            </Row>

            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.temperatureText}
                </Text>
                <Row gap="var(--ggui-spacing-2, 8px)" align="center">
                  <Text size="2xl" is="span">{props.conditionIcon}</Text>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {props.condition}
                  </Text>
                </Row>
              </Stack>

              <Stack
                gap="var(--ggui-spacing-2, 8px)"
                align="end"
              >
                <Row gap="var(--ggui-spacing-2, 8px)" align="center">
                  <Icon name="droplets" size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="label">Humidity: {props.humidityText}</Text>
                </Row>
                <Row gap="var(--ggui-spacing-2, 8px)" align="center">
                  <Icon name="wind" size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="label">Wind: {props.windText}</Text>
                </Row>
              </Stack>
            </Row>

            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin="var(--ggui-spacing-2, 8px)" />

            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                5-Day Forecast
              </Text>
              <Row gap="var(--ggui-spacing-2, 8px)">
                {props.forecast.map((item, index) => (
                  <Box
                    key={`${item.day}-${index}`}
                    padding="var(--ggui-spacing-2, 8px)"
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                  >
                    <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                      <Text variant="caption" weight="medium">
                        {item.day}
                      </Text>
                      <Text size="xl" is="span">{item.icon}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                        {item.highText}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {item.lowText}
                      </Text>
                    </Stack>
                  </Box>
                ))}
              </Row>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

