// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  step: number;
  totalSteps: number;
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
  satisfactionOptions: { value: string; label: string }[];
  featureOptions: string[];
  nameError: string;
  emailError: string;
  canGoNext: boolean;
  isLastStep: boolean;
  canSubmit: boolean;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: string) => void;
  onFeatureToggle: (feature: string, checked: boolean) => void;
  onCommentsChange: (value: string) => void;
  onNext: () => void;
  onBack: () => void;
  onSubmit: () => void;
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const totalSteps = 4;
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const nameError = trimmedName.length === 0 ? 'Name is required' : '';
  const emailError = trimmedEmail.length === 0
    ? 'Email is required'
    : isValidEmail(trimmedEmail)
      ? ''
      : 'Please enter a valid email address';

  const satisfactionOptions = useMemo(
    () => (props.satisfactionLabels ?? []).map((label, index) => ({ value: String(index + 1), label })),
    [props.satisfactionLabels]
  );

  const canGoNext = useMemo(() => {
    if (step === 1) return !nameError && !emailError;
    if (step === 2) return satisfaction.length > 0;
    if (step === 3) return true;
    if (step === 4) return true;
    return false;
  }, [step, nameError, emailError, satisfaction]);

  const onFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => (checked ? [...prev, feature] : prev.filter((item) => item !== feature)));
  }, []);

  const onCommentsChange = useCallback((value: string) => {
    setComments(value.slice(0, 500));
  }, []);

  const onNext = useCallback(() => {
    if (!canGoNext) return;
    setStep((prev) => Math.min(totalSteps + 1, prev + 1));
  }, [canGoNext]);

  const onBack = useCallback(() => {
    setStep((prev) => Math.max(1, prev - 1));
  }, []);

  const onSubmit = useCallback(() => {
    if (step !== totalSteps + 1) return;
    submit({
      name: trimmedName,
      email: trimmedEmail,
      satisfaction: Number(satisfaction),
      features,
      comments,
    });
  }, [comments, features, satisfaction, step, submit, totalSteps, trimmedEmail, trimmedName]);

  return {
    step,
    totalSteps,
    name,
    email,
    satisfaction,
    features,
    comments,
    satisfactionOptions,
    featureOptions: props.featureOptions,
    nameError,
    emailError,
    canGoNext,
    isLastStep: step === totalSteps + 1,
    canSubmit: step === totalSteps + 1,
    onNameChange: setName,
    onEmailChange: setEmail,
    onSatisfactionChange: setSatisfaction,
    onFeatureToggle,
    onCommentsChange,
    onNext,
    onBack,
    onSubmit,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const progressValue = (props.step / (props.totalSteps + 1)) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Heading level={1}>Survey Form</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {props.step === props.totalSteps + 1 ? `Step ${props.step} of ${props.totalSteps + 1} (Review)` : `Step ${props.step} of ${props.totalSteps + 1}`}
          </Text>
          <Progress value={progressValue} max={100} size="md" variant="default" />
        </Stack>

        <Card padding="var(--ggui-spacing-6, 24px)" border radius="lg" shadow="sm">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {props.step === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Input
                  label="Name"
                  value={props.name}
                  onChange={props.onNameChange}
                  required
                  error={props.nameError || undefined}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={props.email}
                  onChange={props.onEmailChange}
                  required
                  error={props.emailError || undefined}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {props.step === 2 && (
              <RadioGroup
                label="How satisfied are you?"
                value={props.satisfaction}
                onChange={props.onSatisfactionChange}
                options={props.satisfactionOptions}
                direction="vertical"
              />
            )}

            {props.step === 3 && (
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Text variant="label">Which features are you interested in?</Text>
                {(props.featureOptions ?? []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={props.features.includes(feature)}
                    onChange={(checked) => props.onFeatureToggle(feature, checked)}
                  />
                ))}
              </Stack>
            )}

            {props.step === 4 && (
              <TextArea
                label="Additional comments"
                value={props.comments}
                onChange={props.onCommentsChange}
                maxLength={500}
                showCount
                rows={6}
                helperText="Optional: share anything else you'd like us to know."
              />
            )}

            {props.step === 5 && (
              <Stack gap="var(--ggui-spacing-3, 12px)">
                <Heading level={4}>Review your answers</Heading>
                <Box
                  padding="var(--ggui-spacing-4, 16px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {props.name}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {props.email}</Text>
                    <Text>
                      <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                      {props.satisfactionOptions.find((item) => item.value === props.satisfaction)?.label || 'N/A'}
                    </Text>
                    <Text>
                      <Text is="span" weight="semibold">Features:</Text>{' '}
                      {props.features.length > 0 ? props.features.join(', ') : 'None selected'}
                    </Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {props.comments || 'No comments'}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Stack>
        </Card>

        <Row gap="var(--ggui-spacing-2, 8px)">
          <Button variant="outline" onClick={props.onBack} disabled={props.step === 1}>
            Back
          </Button>
          <Spacer size="flex" />
          {!props.isLastStep && (
            <Button variant="primary" onClick={props.onNext} disabled={!props.canGoNext}>
              Next
            </Button>
          )}
          {props.isLastStep && (
            <Button variant="primary" onClick={props.onSubmit} disabled={!props.canSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

