// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload =
  | { action: 'move'; taskId: string; data: { column: string } }
  | { action: 'edit'; taskId: string; data: { title: string } }
  | { action: 'create'; taskId: string; data: { title: string; priority: 'low' | 'medium' | 'high'; column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  columns: Array<{ id: string; name: string; tasks: Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }> }>;
  totalTasks: number;
  completedTasks: number;
  latestStreamAction: string;
  connectionNote: string;
  addDrafts: Record<string, { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }>;
  editingTaskId: string | null;
  editingTitle: string;
  moveTask: (taskId: string, column: string) => void;
  beginEdit: (taskId: string, title: string) => void;
  setEditingTitle: (value: string) => void;
  saveEdit: () => void;
  cancelEdit: () => void;
  openAddTask: (columnId: string) => void;
  setAddTitle: (columnId: string, value: string) => void;
  setAddPriority: (columnId: string, value: string) => void;
  createTask: (columnId: string) => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [tasks, setTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>(
    () => (props.tasks || []).map((t, i) => ({ id: t.id || `task-${i}`, title: t.title || 'Untitled task', priority: t.priority || 'medium', assignee: t.assignee || 'NA', column: t.column || 'todo', dueDate: t.dueDate }))
  );
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addDrafts, setAddDrafts] = useState<Record<string, { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }>>({});

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  useEffect(() => {
    setTasks((props.tasks || []).map((t, i) => ({ id: t.id || `task-${i}`, title: t.title || 'Untitled task', priority: t.priority || 'medium', assignee: t.assignee || 'NA', column: t.column || 'todo', dueDate: t.dueDate })));
  }, [props.tasks]);

  useEffect(() => {
    const event = taskChanged.latest;
    if (!event?.task?.id) return;
    const incoming = {
      id: event.task.id,
      title: event.task.title || 'Untitled task',
      priority: event.task.priority || 'medium' as 'low' | 'medium' | 'high',
      assignee: event.task.assignee || 'NA',
      column: event.task.column || 'todo',
      dueDate: event.task.dueDate,
    };
    setTasks((prev) => {
      if (event.action === 'delete') return prev.filter((t) => t.id !== incoming.id);
      const exists = prev.some((t) => t.id === incoming.id);
      if (!exists) return [...prev, incoming];
      return prev.map((t) => (t.id === incoming.id ? { ...t, ...incoming } : t));
    });
  }, [taskChanged.latest]);

  const normalizedColumns = useMemo(
    () => (props.columns || []).map((c, i) => ({ id: c.id || `column-${i}`, name: c.name || `Column ${i + 1}` })),
    [props.columns]
  );

  const columns = useMemo(
    () => normalizedColumns.map((c) => ({ ...c, tasks: tasks.filter((t) => t.column === c.id) })),
    [normalizedColumns, tasks]
  );

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  const moveTask = useCallback((taskId: string, column: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column } : t)));
    taskUpdate({ action: 'move', taskId, data: { column } });
  }, [taskUpdate]);

  const beginEdit = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);

  const saveEdit = useCallback(() => {
    if (!editingTaskId || !editingTitle.trim()) return;
    const updatedTitle = editingTitle.trim();
    setTasks((prev) => prev.map((t) => (t.id === editingTaskId ? { ...t, title: updatedTitle } : t)));
    taskUpdate({ action: 'edit', taskId: editingTaskId, data: { title: updatedTitle } });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTaskId, editingTitle, taskUpdate, tasks]);

  const cancelEdit = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const openAddTask = useCallback((columnId: string) => {
    setAddDrafts((prev) => ({ ...prev, [columnId]: { open: true, title: prev[columnId]?.title || '', priority: prev[columnId]?.priority || 'medium' } }));
  }, []);

  const setAddTitle = useCallback((columnId: string, value: string) => {
    setAddDrafts((prev) => ({ ...prev, [columnId]: { open: true, title: value, priority: prev[columnId]?.priority || 'medium' } }));
  }, []);

  const setAddPriority = useCallback((columnId: string, value: string) => {
    const priority = (value as 'low' | 'medium' | 'high') || 'medium';
    setAddDrafts((prev) => ({ ...prev, [columnId]: { open: true, title: prev[columnId]?.title || '', priority } }));
  }, []);

  const createTask = useCallback((columnId: string) => {
    const draft = addDrafts[columnId];
    if (!draft?.title?.trim()) return;
    const id = `task-${Date.now()}`;
    const newTask = { id, title: draft.title.trim(), priority: draft.priority || 'medium' as 'low' | 'medium' | 'high', assignee: 'NA', column: 'todo' };
    setTasks((prev) => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: id, data: { title: newTask.title, priority: newTask.priority, column: 'todo' } });
    setAddDrafts((prev) => ({ ...prev, [columnId]: { open: false, title: '', priority: 'medium' } }));
  }, [addDrafts, taskUpdate]);

  return {
    columns,
    totalTasks,
    completedTasks,
    latestStreamAction: taskChanged.latest?.action || 'none',
    connectionNote: `Live updates: ${taskChanged.all.length}`,
    addDrafts,
    editingTaskId,
    editingTitle,
    moveTask,
    beginEdit,
    setEditingTitle,
    saveEdit,
    cancelEdit,
    openAddTask,
    setAddTitle,
    setAddPriority,
    createTask,
  };
}

