  onIncreaseQuantity: () => void;
  onAddToCart: () => void;
}

function normalizeSpecifications(items: unknown[] | undefined): Array<{ key: string; value: string }> {
  if (!Array.isArray(items)) return [];
  return items
    .map((item, index) => {
      if (item && typeof item === 'object') {
        const record = item as Record<string, unknown>;
        const key = String(record.key ?? record.name ?? `Spec ${index + 1}`);
        const value = String(record.value ?? record.detail ?? record.spec ?? '—');
        return { key, value };
      }
      return { key: `Spec ${index + 1}`, value: String(item ?? '—') };
    });
}

function normalizeReviews(items: unknown[] | undefined): Array<{ author: string; rating: number; text: string; date: string }> {
  if (!Array.isArray(items)) return [];
  return items.map((item, index) => {
    if (item && typeof item === 'object') {
      const record = item as Record<string, unknown>;
      return {
        author: String(record.author ?? record.name ?? `Reviewer ${index + 1}`),
        rating: Math.max(1, Math.min(5, Number(record.rating ?? 0) || 0)),
        text: String(record.text ?? record.comment ?? 'No review text provided.'),
        date: String(record.date ?? record.createdAt ?? 'N/A'),
      };
    }
    return { author: `Reviewer ${index + 1}`, rating: 0, text: String(item ?? ''), date: 'N/A' };
  });
}

function renderStars(rating: number) {
  const rounded = Math.max(0, Math.min(5, Math.round(rating)));
  return Array.from({ length: 5 }, (_, index) => (
    <Text
      key={`star-${index}`}
>
      {index < rounded ? '★' : '☆'}
    </Text>
  ));
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const productId = props.product.id ?? '';
  const productName = props.product.name ?? 'Unnamed Product';
  const rating = Math.max(0, Math.min(5, props.product.rating ?? 0));
  const reviewCount = props.product.reviewCount ?? 0;
  const stock = Math.max(0, props.product.stock ?? 0);
  const description = props.product.description ?? '';
  const currency = props.product.currency ?? 'USD';
  const priceValue = props.product.price ?? 0;
  const priceText = useMemo(() => {
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency }).format(priceValue);
    } catch {
      const symbols: Record<string, string> = { USD: '$', EUR: '€', GBP: '£', JPY: '¥', INR: '₹', CAD: 'C$', AUD: 'A$' };
      const symbol = symbols[currency.toUpperCase()] ?? currency.toUpperCase();
      return `${symbol} ${priceValue.toFixed(2)}`;
    }
  }, [currency, priceValue]);
  const specifications = useMemo(() => normalizeSpecifications(props.product.specifications), [props.product.specifications]);
  const reviews = useMemo(() => normalizeReviews(props.product.reviews), [props.product.reviews]);
  const [quantity, setQuantity] = useState(1);

  useEffect(() => {
    setQuantity(1);
  }, [productId]);

  useEffect(() => {
    setQuantity((prev) => Math.min(Math.max(stock, 1), Math.max(1, prev)));
  }, [stock]);

  const onDecreaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const onIncreaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.min(Math.max(stock, 1), prev + 1));
  }, [stock]);

  const onAddToCart = useCallback(() => {
    if (!productId || stock <= 0) return;
    addToCart({ productId, quantity });
  }, [addToCart, productId, quantity, stock]);

  return {
    productId,
    productName,
    priceText,
    rating,
    reviewCount,
    stock,
    description,
    specifications,
    reviews,
    quantity,
    canDecrease: quantity > 1,
    canIncrease: quantity < Math.max(stock, 1),
    canAddToCart: stock > 0 && productId.length > 0,
    onDecreaseQuantity,
    onIncreaseQuantity,
    onAddToCart,
  };
}

