}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  title: string;
  participantCount: number;
  currentUser: string;
  messages: Array<{ sender: string; text: string; timestamp: string }>;
  typingSenders: string[];
  draft: string;
  setDraft: (value: string) => void;
  onSend: () => void;
  onDraftKeyDown: (event: React.KeyboardEvent<HTMLInputElement>) => void;
}

function formatTimestamp(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [messagesState, setMessagesState] = useState<Array<{ sender: string; text: string; timestamp: string }>>(
    props.messages.map((m) => ({
      sender: m.sender ?? 'Unknown',
      text: m.text ?? '',
      timestamp: m.timestamp ?? new Date().toISOString(),
    }))
  );
  const [draft, setDraft] = useState('');
  const [activeTypers, setActiveTypers] = useState<Set<string>>(new Set());

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  useEffect(() => {
    if (!message.latest) return;
    setMessagesState((prev) => [
      ...prev,
      {
        sender: message.latest?.sender ?? 'Unknown',
        text: message.latest?.text ?? '',
        timestamp: message.latest?.timestamp ?? new Date().toISOString(),
      },
    ]);
  }, [message.latest]);

  useEffect(() => {
    const event = typing.latest;
    if (!event?.sender || event.sender === props.currentUser) return;
    setActiveTypers((prev) => {
      const next = new Set(prev);
      if (event.active) next.add(event.sender);
      else next.delete(event.sender);
      return next;
    });
  }, [typing.latest, props.currentUser]);

  const onSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setMessagesState((prev) => [
      ...prev,
      { sender: props.currentUser, text: trimmed, timestamp },
    ]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const onDraftKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        onSend();
      }
    },
    [onSend]
  );

  return {
    title: props.title,
    participantCount: props.participantCount,
    currentUser: props.currentUser,
    messages: messagesState,
    typingSenders: Array.from(activeTypers),
    draft,
    setDraft,
    onSend,
    onDraftKeyDown,
  };
}

