interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}
// DO NOT EDIT types below — auto-generated from the data contract


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewStock {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
  isPositive: boolean;
  isFlashing: boolean;
}

interface ViewProps {
  stocks: ViewStock[];
  lastUpdatedLabel: string;
  marketStatusLabel: string;
  isMarketOpen: boolean;
}

function formatCurrency(value: number) {
  return `$${value.toFixed(2)}`;
}

function formatSigned(value: number) {
  const sign = value >= 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}`;
}

function formatPercent(value: number) {
  const sign = value >= 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}%`;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [stockMap, setStockMap] = useState<Record<string, ViewStock>>(() => {
    const initial: Record<string, ViewStock> = {};
    props.stocks.forEach((stock) => {
      const symbolKey = stock.symbol?.trim().toUpperCase();
      if (!symbolKey) return;
      const price = stock.price ?? 0;
      const change = stock.change ?? 0;
      const changePercent = stock.changePercent ?? 0;
      initial[symbolKey] = {
        symbol: symbolKey,
        name: stock.name ?? 'Unknown Company',
        price,
        change,
        changePercent,
        isPositive: change >= 0,
        isFlashing: false,
      };
    });
    return initial;
  });
  const [lastUpdatedAt, setLastUpdatedAt] = useState<Date | null>(null);
  const [timeTick, setTimeTick] = useState<number>(Date.now());

  // DO NOT EDIT wire hooks below — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const flashTimeoutsRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  useEffect(() => {
    return () => {
      Object.values(flashTimeoutsRef.current).forEach((timeoutId) => clearTimeout(timeoutId));
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) {
      return;
    }
    const incoming = priceUpdate.latest;
    const key = incoming.symbol?.trim().toUpperCase();
    if (!key) return;
    setStockMap((prev) => {
      const existing = prev[key];
      if (!existing) {
        return prev;
      }
      const nextPrice = incoming.price ?? existing.price;
      const nextChange = incoming.change ?? existing.change;
      const nextChangePercent = incoming.changePercent ?? existing.changePercent;
      return {
        ...prev,
        [key]: {
          ...existing,
          price: nextPrice,
          change: nextChange,
          changePercent: nextChangePercent,
          isPositive: nextChange >= 0,
          isFlashing: true,
        },
      };
    });

    const eventTime = (incoming as { timestamp?: string }).timestamp;
    const parsedEventTime = eventTime ? new Date(eventTime) : null;
    setLastUpdatedAt(parsedEventTime && !Number.isNaN(parsedEventTime.getTime()) ? parsedEventTime : new Date());

    if (flashTimeoutsRef.current[key]) {
      clearTimeout(flashTimeoutsRef.current[key]);
    }
    flashTimeoutsRef.current[key] = setTimeout(() => {
      setStockMap((prev) => {
        const current = prev[key];
        if (!current) return prev;
        return { ...prev, [key]: { ...current, isFlashing: false } };
      });
    }, 500);
  }, [priceUpdate.latest]);

  const stocks = useMemo(() => Object.values(stockMap), [stockMap]);
  const latestStatus = marketStatus.latest?.status ?? 'closed';
  const marketStatusLabel = latestStatus;
  const isMarketOpen = latestStatus === 'open';

  useEffect(() => {
    if (!marketStatus.latest) {
      return;
    }
    const parsed = marketStatus.latest.timestamp ? new Date(marketStatus.latest.timestamp) : null;
    if (parsed && !Number.isNaN(parsed.getTime())) {
      setLastUpdatedAt(parsed);
      return;
    }
    setLastUpdatedAt(new Date());
  }, [marketStatus.latest]);

  useEffect(() => {
    const intervalId = setInterval(() => setTimeTick(Date.now()), 1000);
    return () => clearInterval(intervalId);
  }, []);

  return {
    stocks,
    lastUpdatedLabel: lastUpdatedAt ? `${lastUpdatedAt.toLocaleTimeString()} (${new Date(timeTick).toLocaleTimeString()})` : 'Waiting for updates…',
    marketStatusLabel,
    isMarketOpen,
  };
}

