// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete: (data: ActionCompletePayload) => void; // Completion callback with collected profile data
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Helper constants
const FALLBACK_AVATARS = ['😀', '🚀', '🎨', '🧠'];
const FALLBACK_ROLES = ['Developer', 'Designer', 'Manager', 'Other'];

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
}

// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  step: number;
  progressValue: number;
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
  avatarOptions: string[];
  roleOptions: string[];
  nameError?: string;
  emailError?: string;
  canGoBack: boolean;
  canGoNext: boolean;
  isLastStep: boolean;
  isSubmitting: boolean;
  summaryItems: Array<{ label: string; value: string }>;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onAvatarChange: (value: string) => void;
  onRoleChange: (value: string) => void;
  onEmailNotificationsChange: (value: boolean) => void;
  onThemeChange: (value: string) => void;
  onBack: () => void;
  onNext: () => void;
  onComplete: () => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const initial = props.initialProfile ?? {};
  const avatarOptionsInput = props.avatarOptions ?? [];
  const roleOptionsInput = props.roleOptions ?? [];
  const [step, setStep] = useState(1);
  const [name, setName] = useState(initial.name ?? '');
  const [email, setEmail] = useState(initial.email ?? '');
  const [avatar, setAvatar] = useState(initial.avatar ?? '');
  const [role, setRole] = useState(initial.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(initial.emailNotifications ?? false);
  const [theme, setTheme] = useState(initial.theme ?? 'light');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const hasCompletedRef = useRef(false);

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const avatarOptions = avatarOptionsInput.length > 0 ? avatarOptionsInput : FALLBACK_AVATARS;
  const roleOptions = roleOptionsInput.length > 0 ? roleOptionsInput : FALLBACK_ROLES;

  useEffect(() => {
    if (roleOptions.length === 0) return;
    if (!role || !roleOptions.includes(role)) {
      setRole(roleOptions[0]);
    }
  }, [role, roleOptions]);

  const nameError = name.trim() ? undefined : 'Name is required.';
  const emailError = email.trim() ? (isValidEmail(email) ? undefined : 'Please enter a valid email.') : 'Email is required.';
  const isStep1Valid = !nameError && !emailError && Boolean(avatar);
  const isStep2Valid = Boolean(role);
  const canGoNext = step === 1 ? Boolean(isStep1Valid) : Boolean(isStep2Valid);
  const canGoBack = step > 1;
  const isLastStep = step === 3;
  const progressValue = (step / 3) * 100;

  const summaryItems = [
    { label: 'Name', value: name || '-' },
    { label: 'Email', value: email || '-' },
    { label: 'Avatar', value: avatar || '-' },
    { label: 'Role', value: role || '-' },
    { label: 'Email Notifications', value: emailNotifications ? 'On' : 'Off' },
    { label: 'Theme', value: theme === 'dark' ? 'Dark' : 'Light' },
  ];

  const onBack = () => setStep((prev) => Math.max(1, prev - 1));
  const onNext = () => {
    if (step < 3 && canGoNext) setStep((prev) => prev + 1);
  };
  const onComplete = () => {
    if (hasCompletedRef.current || isSubmitting || !isStep1Valid || !isStep2Valid || !avatar || !role) return;
    const normalizedTheme = String(theme).toLowerCase() === 'dark' ? 'dark' : 'light';
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme: normalizedTheme,
    };
    hasCompletedRef.current = true;
    setIsSubmitting(true);
    props.onComplete(payload);
    complete(payload);
  };

  return {
    step,
    progressValue,
    name,
    email,
    avatar,
    role,
    emailNotifications,
    theme,
    avatarOptions,
    roleOptions,
    nameError,
    emailError,
    canGoBack,
    canGoNext,
    isLastStep,
    summaryItems,
    onNameChange: setName,
    onEmailChange: setEmail,
    onAvatarChange: setAvatar,
    onRoleChange: setRole,
    onEmailNotificationsChange: setEmailNotifications,
    onThemeChange: setTheme,
    onBack,
    onNext,
    onComplete,
    isSubmitting,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const stepTitles = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Heading level={2}>Onboarding Wizard</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {props.step} of 3 · {stepTitles[props.step - 1]}</Text>
          <Progress value={props.progressValue} max={100} />
        </Stack>

        <Card padding="var(--ggui-spacing-6, 24px)" border radius="lg">
          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {props.step === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Input label="Name" value={props.name} onChange={props.onNameChange} required error={props.nameError} placeholder="Enter your name" />
                <Input label="Email" type="email" value={props.email} onChange={props.onEmailChange} required error={props.emailError} placeholder="you@example.com" />
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="label">Choose Avatar (required)</Text>
                  <Row gap="var(--ggui-spacing-2, 8px)">
                    {props.avatarOptions.map((emoji) => (
                      <Button key={emoji} variant={props.avatar === emoji ? 'primary' : 'outline'} onClick={() => props.onAvatarChange(emoji)} aria-label={`Select avatar ${emoji}`}>
                        {emoji}
                      </Button>
                    ))}
                  </Row>
                  {!props.avatar && <Text variant="caption" color="var(--ggui-color-error, #dc2626)">Please select an avatar.</Text>}
                </Stack>
              </Stack>
            )}

            {props.step === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Select
                  label="Role"
                  value={props.role}
                  onChange={props.onRoleChange}
                  options={props.roleOptions.map((option) => ({ value: option, label: option }))}
                  placeholder="Select your role"
                  required
                />
                <Toggle label="Email notifications" checked={props.emailNotifications} onChange={props.onEmailNotificationsChange} />
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="label">Theme preference</Text>
                  <Toggle
                    label={String(props.theme).toLowerCase() === 'dark' ? 'Dark mode' : 'Light mode'}
                    checked={String(props.theme).toLowerCase() === 'dark'}
                    onChange={(checked) => props.onThemeChange(checked ? 'dark' : 'light')}
                  />
                </Stack>
              </Stack>
            )}

            {props.step === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={4}>Review your setup</Heading>
                <Card padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    {props.summaryItems.map((item) => (
                      <Row key={item.label} justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.label}</Text>
                        <Text weight="medium">{item.value}</Text>
                      </Row>
                    ))}
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>
        </Card>

        <Row gap="var(--ggui-spacing-2, 8px)">
          {props.canGoBack && <Button variant="ghost" onClick={props.onBack}>Go Back</Button>}
          <Spacer size="flex" />
          {!props.isLastStep ? (
            <Button onClick={props.onNext} disabled={!props.canGoNext}>Next</Button>
          ) : (
            <Button onClick={props.onComplete} disabled={props.isSubmitting}>{props.isSubmitting ? 'Completed' : 'Complete Setup'}</Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}
